// --- Token Management ---

const (
	hmacSecret       = "mesh-internal-secret-key-2024"
	tokenHeader      = "x-mesh-auth-token"
	serviceHeader    = "x-mesh-service-id"
	tokenExpiration  = 5 * time.Minute
)

// TokenInfo represents parsed token information
type TokenInfo struct {
	ServiceID string
	IssuedAt  time.Time
	Signature string
}

// TokenStore manages valid service tokens
type TokenStore struct {
	mu              sync.RWMutex
	validServices   map[string]bool
	revokedTokens   map[string]time.Time
}

func NewTokenStore() *TokenStore {
	ts := &TokenStore{
		validServices: map[string]bool{
			"service-a":    true,
			"service-b":    true,
			"service-c":    true,
			"api-gateway":  true,
			"auth-service": true,
		},
		revokedTokens: make(map[string]time.Time),
	}
	// Clean up revoked tokens periodically
	go ts.cleanupLoop()
	return ts
}

func (ts *TokenStore) cleanupLoop() {
	ticker := time.NewTicker(1 * time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		ts.mu.Lock()
		now := time.Now()
		for token, revokedAt := range ts.revokedTokens {
			if now.Sub(revokedAt) > tokenExpiration*2 {
				delete(ts.revokedTokens, token)
			}
		}
		ts.mu.Unlock()
	}
}

func (ts *TokenStore) IsValidService(serviceID string) bool {
	ts.mu.RLock()
	defer ts.mu.RUnlock()
	return ts.validServices[serviceID]
}

func (ts *TokenStore) IsRevoked(token string) bool {
	ts.mu.RLock()
	defer ts.mu.RUnlock()
	_, revoked := ts.revokedTokens[token]
	return revoked
}

func (ts *TokenStore) RevokeToken(token string) {
	ts.mu.Lock()
	defer ts.mu.Unlock()
	ts.revokedTokens[token] = time.Now()
}

// GenerateToken creates a signed token for a service
func GenerateToken(serviceID string) string {
	issuedAt := time.Now().Unix()
	payload := fmt.Sprintf("%s:%d", serviceID, issuedAt)
	mac := hmac.New(sha256.New, []byte(hmacSecret))
	mac.Write([]byte(payload))
	signature := hex.EncodeToString(mac.Sum(nil))
	return fmt.Sprintf("%s.%s", payload, signature)
}

// ParseAndValidateToken parses and validates a token
func ParseAndValidateToken(token string) (*TokenInfo, error) {
	parts := strings.SplitN(token, ".", 2)
	if len(parts) != 2 {
		return nil, fmt.Errorf("invalid token format")
	}

	payload := parts[0]
	signature := parts[1]

	// Verify HMAC signature
	mac := hmac.New(sha256.New, []byte(hmacSecret))
	mac.Write([]byte(payload))
	expectedSig := hex.EncodeToString(mac.Sum(nil))

	if !hmac.Equal([]byte(signature), []byte(expectedSig)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Parse payload
	payloadParts := strings.SplitN(payload, ":", 2)
	if len(payloadParts) != 2 {
		return nil, fmt.Errorf("invalid token payload")
	}

	serviceID := payloadParts[0]
	var issuedAtUnix int64
	_, err := fmt.Sscanf(payloadParts[1], "%d", &issuedAtUnix)
	if err != nil {
		return nil, fmt.Errorf("invalid token timestamp: %v", err)
	}

	issuedAt := time.Unix(issuedAtUnix, 0)

	// Check expiration
	if time.Since(issuedAt) > tokenExpiration {
		return nil, fmt.Errorf("token expired")
	}

	return &TokenInfo{
		ServiceID: serviceID,
		IssuedAt:  issuedAt,
		Signature: signature,
	}, nil
}

