// AuthInterceptor is a unary server interceptor for authentication logging
func AuthInterceptor(tokenStore *TokenStore) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		start := time.Now()

		// Log incoming request
		log.Printf("Incoming RPC: %s", info.FullMethod)

		// Extract metadata for logging
		md, ok := metadata.FromIncomingContext(ctx)
		if ok {
			if serviceIDs := md.Get(serviceHeader); len(serviceIDs) > 0 {
				log.Printf("Request from service: %s", serviceIDs[0])
			}
		}

		// Call the handler
		resp, err := handler(ctx, req)

		// Log completion
		duration := time.Since(start)
		if err != nil {
			log.Printf("RPC %s failed after %v: %v", info.FullMethod, duration, err)
		} else {
			log.Printf("RPC %s completed in %v", info.FullMethod, duration)
		}

		return resp, err
	}
}

// RateLimitInterceptor provides basic rate limiting per service
type RateLimiter struct {
	mu       sync.Mutex
	requests map[string][]time.Time
	limit    int
	window   time.Duration
}

func NewRateLimiter(limit int, window time.Duration) *RateLimiter {
	return &RateLimiter{
		requests: make(map[string][]time.Time),
		limit:    limit,
		window:   window,
	}
}

func (rl *RateLimiter) Allow(serviceID string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	now := time.Now()
	windowStart := now.Add(-rl.window)

	// Clean old entries
	var valid []time.Time
	for _, t := range rl.requests[serviceID] {
		if t.After(windowStart) {
			valid = append(valid, t)
		}
	}
	rl.requests[serviceID] = valid

	if len(valid) >= rl.limit {
		return false
	}

	rl.requests[serviceID] = append(rl.requests[serviceID], now)
	return true
}

func RateLimitInterceptor(limiter *RateLimiter) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		md, ok := metadata.FromIncomingContext(ctx)
		if ok {
			if serviceIDs := md.Get(serviceHeader); len(serviceIDs) > 0 {
				if !limiter.Allow(serviceIDs[0]) {
					return nil, status.Errorf(codes.ResourceExhausted,
						"rate limit exceeded for service %s", serviceIDs[0])
				}
			}
		}
		return handler(ctx, req)
	}
}

